import { useEffect, useState } from 'react';
import { getAll, remove } from '../services/api';
import { useNavigate } from 'react-router-dom';

export default function View() {
  const [data, setData] = useState([]);
  const [search, setSearch] = useState("");
  const navigate = useNavigate();

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    const res = await getAll();
    setData(res.data);
  };

  // SEARCH FILTER
  const filtered = data.filter(d =>
    d.application_id.toString().includes(search)
  );

  return (
    <div className="container">
      <div className="card">
        <h2>All Applications</h2>

        <input
          placeholder="Search by Application ID"
          onChange={(e) => setSearch(e.target.value)}
        />

        <table>
          <thead>
            <tr>
              <th>ID</th>
              <th>Applicant ID</th>
              <th>Documents</th>
              <th>Police Verification</th>
              <th>Status</th>
              <th>Actions</th>
            </tr>
          </thead>

          <tbody>
            {filtered.map(d => (
              <tr key={d.application_id}>
                <td>{d.application_id}</td>
                <td>{d.applicant_id}</td>
                <td>{d.documents_submitted ? "Yes" : "No"}</td>
                <td>{d.police_verification}</td>

                {/* STATUS WITH COLOR */}
                <td>
                  <span className={`status ${
                    d.status === "Pending" ? "pending" :
                    d.status === "Verified" ? "verified" :
                    "generated"
                  }`}>
                    {d.status}
                  </span>
                </td>

                <td>
                  <button
                    onClick={() => navigate(`/update?id=${d.application_id}`)}
                  >
                    Edit
                  </button>

                  <button
                    onClick={() => {
                      remove(d.application_id).then(fetchData);
                    }}
                  >
                    Delete
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}
